// Dinic 算法
#include <bits/stdc++.h>
using namespace std;

const int N=210,M=1e4+10;
const long long INF=1e18;

int n,m,s,t;
int head[N],ver[M],edge[M],nxt[M],tot=1;
int d[N],now[N];

void add(int u,int v,int w){
    ver[++tot]=v,edge[tot]=w,nxt[tot]=head[u],head[u]=tot;
    ver[++tot]=u,edge[tot]=0,nxt[tot]=head[v],head[v]=tot;
}

bool bfs(){
    memset(d,0,sizeof(d));
    queue<int> q;
    q.push(s),d[s]=1,now[s]=head[s];
    while(q.size()){
        int x=q.front();
        q.pop();
        for(int i=head[x],y;i;i=nxt[i])
            if(!d[y=ver[i]] && edge[i]){
                d[y]=d[x]+1,now[y]=head[y];
                if(y==t)
                    return 1;
                q.push(y);
            }
    }
    return 0;
}

long long Dinic(int x,long long flow){
    if(x==t)
        return flow;
    long long res=0;
    for(int i=now[x],y;i && res<flow;i=nxt[i]){
        y=ver[i],now[x]=i;
        if(d[y]==d[x]+1 && edge[i]){
            long long tmp=Dinic(y,min(1ll*edge[i],flow-res));
            if(!tmp)
                d[y]=0;
            edge[i]-=tmp,edge[i^1]+=tmp;
            res+=tmp;
        }
    }
    return res;
}

int main(){
    scanf("%d%d%d%d",&n,&m,&s,&t);
    for(int i=1,u,v,w;i<=m;i++){
        scanf("%d%d%d",&u,&v,&w);
        add(u,v,w);
    }
    long long flow,max_flow=0;
    while(bfs())
        while(flow=Dinic(s,INF))
            max_flow+=flow;
    printf("%lld",max_flow);
    return 0;
}
